62	// Command registration is now handled by command_factory.go
63	// This file contains the CLI interface layer and pure business logic functions
64	
65	// InitResult contains the result of an initialization operation
66	type InitResult struct {
67		ConfigCreated bool
68		LibraryExists bool
69		Config        *config.Config
70	}
