72	// runInit implements the CLI interface layer for the init command
73	func (f *CommandFactory) runInit(cmd *cobra.Command, args []string) error {
74		// Extract flags from cobra.Command
75		initForce, _ := cmd.Flags().GetBool("force")
76		initNoGit, _ := cmd.Flags().GetBool("no-git")
77		initSilent, _ := cmd.Flags().GetBool("silent")
78		initSkipClaude, _ := cmd.Flags().GetBool("skip-claude-injection")
79		initRepository, _ := cmd.Flags().GetString("repository")
80		initBranch, _ := cmd.Flags().GetString("branch")
81	
82		// Create options struct for business logic
83		opts := InitOptions{
84			Force:               initForce,
85			NoGit:               initNoGit,
86			Silent:              initSilent,
87			SkipClaudeInjection: initSkipClaude,
88			Repository:          initRepository,
89			Branch:              initBranch,
90			DDxVersion:          f.Version,
91		}
92	
93		// Handle user output
94		if !opts.Silent {
95			_, _ = fmt.Fprint(cmd.OutOrStdout(), "🚀 Initializing DDx in current project...\n")
96			_, _ = fmt.Fprintln(cmd.OutOrStdout())
97		}
98	
99		// Call pure business logic function
100		_, err := initProject(f.WorkingDir, opts)
101		if err != nil {
102			cmd.SilenceUsage = true
103			return err
104		}
105	
106		// Handle user output based on results
107		if !opts.Silent {
108			_, _ = fmt.Fprint(cmd.OutOrStdout(), "✅ DDx initialized successfully!\n")
109			_, _ = fmt.Fprintln(cmd.OutOrStdout())
110			_, _ = fmt.Fprint(cmd.OutOrStdout(), "Next steps:\n")
111			_, _ = fmt.Fprint(cmd.OutOrStdout(), "  ddx install helix   - Install HELIX workflow (optional)\n")
112			_, _ = fmt.Fprint(cmd.OutOrStdout(), "  ddx doctor          - Check installation health\n")
113			_, _ = fmt.Fprintln(cmd.OutOrStdout())
114		}
115	
116		return nil
117	}
