119	// initProject is the pure business logic function for project initialization
120	func initProject(workingDir string, opts InitOptions) (*InitResult, error) {
121		result := &InitResult{}
122	
123		// Validate git repository unless --no-git flag is used
124		if !opts.NoGit {
125			if err := validateGitRepo(workingDir); err != nil {
126				return nil, NewExitError(1, err.Error())
127			}
128		}
129	
130		// Guard against running inside an execute-bead context.
131		if os.Getenv("DDX_EXECUTE_BEAD_ID") != "" {
132			return nil, NewExitError(1,
133				"ddx init cannot be run inside an execute-bead context (DDX_EXECUTE_BEAD_ID is set)")
134		}
135		// Guard against running inside an execute-bead worktree. These are isolated
136		// execution environments under .ddx/.execute-bead-wt-*; running ddx init
137		// inside one would overwrite the project's .ddx/ config and beads.jsonl.
138		if isExecuteBeadWorktree(workingDir) {
139			return nil, NewExitError(1,
140				"ddx init cannot be run inside an execute-bead worktree (.ddx/.execute-bead-wt-*)")
141		}
142	
143		// Guard against nested workspaces: if a parent directory already has a
144		// .ddx/ workspace, refuse to create a second one in a subdirectory.
145		// This prevents the split-tracker bug where commands from different
146		// directories operate on different .ddx/beads.jsonl files.
147		if parent := findParentDDxWorkspace(workingDir); parent != "" {
148			return nil, NewExitError(1, fmt.Sprintf(
149				".ddx/ workspace already exists at %s. "+
150					"DDx anchors to the git repository root; run commands from any directory.",
151				parent))
152		}
153	
154		// Check if config already exists
155		configPath := ddxroot.JoinProject(workingDir, "config.yaml")
156		if _, err := os.Stat(configPath); err == nil {
157			if !opts.Force {
158				// Config exists and --force not used - exit code 2 per contract
159				return nil, NewExitError(2, ".ddx/config.yaml already exists. Use --force to overwrite.")
160			}
161			// With --force flag, we proceed to overwrite without backup
162		}
163	
164		// Check if library path exists using working directory
165		cfg, err := config.LoadWithWorkingDir(workingDir)
166		libraryExists := true
167		if err != nil || cfg.Library == nil || cfg.Library.Path == "" {
168			libraryExists = false
169		} else if _, err := os.Stat(filepath.Join(workingDir, cfg.Library.Path)); os.IsNotExist(err) {
170			libraryExists = false
171		}
172		result.LibraryExists = libraryExists
173	
174		// Create configuration with defaults
175		localConfig := createProjectConfig()
176	
177		// Apply default values (including repository settings)
178		localConfig.ApplyDefaults()
179	
180		// Add validation during creation
181		if err := validateConfiguration(localConfig); err != nil {
182			return nil, NewExitError(1, fmt.Sprintf("Configuration validation failed: %v", err))
183		}
184	
185		// Try to load existing config to preserve settings (even if library doesn't exist yet)
186		if cfg != nil && err == nil {
187			// Note: Version is NOT copied - always upgrade to current version via ApplyDefaults
188			// Copy library settings if they exist (unless overridden by flags)
189			if cfg.Library != nil && localConfig.Library != nil {
190				if cfg.Library.Path != "" {
191					localConfig.Library.Path = cfg.Library.Path
192				}
193				if cfg.Library.Repository != nil && localConfig.Library.Repository != nil {
194					// Only copy existing values if not overridden by flags
195					if opts.Repository == "" && cfg.Library.Repository.URL != "" {
196						localConfig.Library.Repository.URL = cfg.Library.Repository.URL
197					}
198					if opts.Branch == "" && cfg.Library.Repository.Branch != "" {
199						localConfig.Library.Repository.Branch = cfg.Library.Repository.Branch
200					}
201				}
202			}
203		}
204	
205		// Apply flag overrides AFTER loading existing config (flags have highest priority)
206		if opts.Repository != "" {
207			if localConfig.Library == nil {
208				localConfig.Library = &config.LibraryConfig{}
209			}
210			if localConfig.Library.Repository == nil {
211				localConfig.Library.Repository = &config.RepositoryConfig{}
212			}
213			localConfig.Library.Repository.URL = opts.Repository
214		}
215		if opts.Branch != "" {
216			if localConfig.Library == nil {
217				localConfig.Library = &config.LibraryConfig{}
218			}
219			if localConfig.Library.Repository == nil {
220				localConfig.Library.Repository = &config.RepositoryConfig{}
221			}
222			localConfig.Library.Repository.Branch = opts.Branch
223		}
224	
225		// Create .ddx directory first
226		localDDxPath := ddxroot.JoinProject(workingDir)
227		if err := os.MkdirAll(localDDxPath, 0755); err != nil {
228			return nil, NewExitError(1, fmt.Sprintf("Failed to create .ddx directory: %v", err))
229		}
230	
231		// Save local configuration using ConfigLoader
232		loader, err := config.NewConfigLoaderWithWorkingDir(workingDir)
233		if err != nil {
234			return nil, NewExitError(1, fmt.Sprintf("Failed to create config loader: %v", err))
235		}
236		if err := loader.SaveConfig(localConfig, ".ddx/config.yaml"); err != nil {
237			return nil, NewExitError(1, fmt.Sprintf("Failed to save configuration: %v", err))
238		}
239		result.ConfigCreated = true
240	
241		if err := ensureProjectGitignoreRules(workingDir, initGitignoreRules); err != nil {
242			return nil, NewExitError(1, fmt.Sprintf("Failed to update .gitignore: %v", err))
243		}
244		if !opts.NoGit {
245			if err := untrackLegacyRunStateFiles(context.Background(), workingDir); err != nil {
246				return nil, NewExitError(1, fmt.Sprintf("Failed to migrate legacy run-state tracking: %v", err))
247			}
248		}
249	
250		// Create library directory structure (offline-safe — plugin install may fail).
251		libraryPath := filepath.Join(workingDir, localConfig.Library.Path)
252		for _, sub := range []string{"prompts", "personas", "patterns", "templates", "configs"} {
253			_ = os.MkdirAll(filepath.Join(libraryPath, sub), 0755)
254		}
255	
256		// Sweep stale pre-consolidation ddx-* skill dirs from harness-visible
257		// targets so leftover skills from older DDx versions don't shadow the
258		// package-installer outputs. The current package installs a single `ddx`
259		// skill into .agents/skills/ and .claude/skills/; unrelated third-party
260		// skills (anything not prefixed `ddx-` or matching the kept name) are
261		// preserved.
262		bootstrapSkillNames := []string{"ddx"}
263		for _, dir := range []string{
264			filepath.Join(workingDir, ".agents", "skills"),
265			filepath.Join(workingDir, ".claude", "skills"),
266		} {
267			_ = os.MkdirAll(dir, 0755)
268			cleanupBootstrapSkills(dir, bootstrapSkillNames)
269		}
270	
271		// Install the default ddx plugin through the embedded package installer.
272		// This produces .ddx/plugins/ddx, .agents/skills/ddx, and .claude/skills/ddx
273		// from the //go:embed'd library tree, so init works offline without a
274		// separate bootstrap skill copier or remote tarball download.
275		reg := registry.BuiltinRegistry()
276		if pkg, err := reg.Find("ddx"); err == nil {
277			var oldFiles []string
278			if state, _ := registry.LoadState(); state != nil {
279				if old := state.FindInstalled(pkg.Name); old != nil {
280					oldFiles = append([]string{}, old.Files...)
281				}
282			}
283	
284			if entry, installErr := registry.InstallPackageFromFS(pkg, defaultplugin.FS(), workingDir); installErr != nil {
285				_, _ = fmt.Fprintf(os.Stderr, "Warning: could not install default ddx plugin from embedded package: %v\n", installErr)
286			} else {
287				_ = removeStaleFilesFromInstall(oldFiles, entry.Files)
288	
289				state, _ := registry.LoadState()
290				if state == nil {
291					state = &registry.InstalledState{}
292				}
293				state.AddOrUpdate(entry)
294				_ = registry.SaveState(state)
295			}
296		}
297	
298		// Write .ddx/versions.yaml (system-managed, tracks binary version)
299		writeProjectVersions(workingDir, opts.DDxVersion)
300	
301		if !opts.NoGit {
302			// Inject initial meta-prompt if the prompt file actually exists (unless explicitly skipped)
303			if !opts.SkipClaudeInjection {
304				if err := injectInitialMetaPrompt(localConfig, workingDir); err != nil {
305					// Don't fail - meta-prompt is optional enhancement
306					// Only warn if the specific prompt file exists but has issues
307					promptPath := localConfig.GetMetaPrompt()
308					if promptPath != "" {
309						fullPromptPath := filepath.Join(workingDir, localConfig.Library.Path, promptPath)
310						if _, statErr := os.Stat(fullPromptPath); statErr == nil {
311							_, _ = fmt.Fprintf(os.Stderr, "Warning: Failed to inject meta-prompt: %v\n", err)
312						}
313					}
314				}
315			}
316	
317			// Generate AGENTS.md with guidance for AI agents working in this repo.
318			generateAgentsMD(workingDir)
319	
320			// Commit config and versions files
321			ctx := context.Background()
322			gitAdd := gitpkg.Command(ctx, workingDir, "add", ".ddx/config.yaml", ".ddx/versions.yaml", "AGENTS.md", ".gitignore")
323			if err := gitAdd.Run(); err != nil {
324				return nil, NewExitError(1, fmt.Sprintf("Failed to stage config file: %v", err))
325			}
326	
327			gitCommit := gitpkg.Command(ctx, workingDir, "commit", "-m", "chore: add DDx configuration")
328			if err := gitCommit.Run(); err != nil {
329				return nil, NewExitError(1, fmt.Sprintf("Failed to commit config file: %v", err))
330			}
331	
332			// Enable per-worktree git config so that `git config --local` inside
333			// linked worktrees (e.g. execute-bead worktrees) writes to a
334			// worktree-specific file rather than the shared .git/config. This
335			// prevents agents from accidentally corrupting repo-level settings like
336			// core.bare when running in an isolated worktree.
337			gitWorktreeCfg := gitpkg.Command(ctx, workingDir, "config", "extensions.worktreeConfig", "true")
338			_ = gitWorktreeCfg.Run() // best-effort; older git versions may not support it
339		}
340	
341		// Store config for CLI layer to use for sync setup
342		result.Config = localConfig
343	
344		// Configuration already saved above
345	
346		return result, nil
347	}
