349	// writeProjectVersions writes .ddx/versions.yaml with the current binary version.
350	// This file is system-managed and committed to git for version gating.
351	func writeProjectVersions(workingDir, ddxVersion string) {
352		if ddxVersion == "" || ddxVersion == "dev" {
353			ddxVersion = "dev"
354		}
355		versionsPath := ddxroot.JoinProject(workingDir, "versions.yaml")
356		content := fmt.Sprintf("ddx_version: %q\n", ddxVersion)
357		if err := os.WriteFile(versionsPath, []byte(content), 0644); err != nil {
358			_, _ = fmt.Fprintf(os.Stderr, "Warning: could not write .ddx/versions.yaml: %v\n", err)
359		}
360	}
361	
362	// readProjectVersions reads ddx_version from .ddx/versions.yaml.
363	// Returns empty string if the file doesn't exist or can't be parsed.
364	func readProjectVersions(workingDir string) string {
365		versionsPath := ddxroot.JoinProject(workingDir, "versions.yaml")
366		data, err := os.ReadFile(versionsPath)
367		if err != nil {
368			return ""
369		}
370		// Simple parse: look for ddx_version: "x.y.z" or ddx_version: x.y.z
371		for _, line := range strings.Split(string(data), "\n") {
372			line = strings.TrimSpace(line)
373			if strings.HasPrefix(line, "ddx_version:") {
374				val := strings.TrimPrefix(line, "ddx_version:")
375				val = strings.TrimSpace(val)
376				val = strings.Trim(val, `"'`)
377				return val
378			}
379		}
380		return ""
381	}
