383	func cleanupBootstrapSkills(targetDir string, keep []string) {
384		entries, err := os.ReadDir(targetDir)
385		if err != nil {
386			return
387		}
388	
389		keepSet := make(map[string]bool, len(keep))
390		for _, name := range keep {
391			keepSet[name] = true
392		}
393	
394		for _, entry := range entries {
395			name := entry.Name()
396			if !strings.HasPrefix(name, "ddx-") {
397				continue
398			}
399			if keepSet[name] {
400				continue
401			}
402	
403			skillDir := filepath.Join(targetDir, name)
404			if _, err := os.Stat(filepath.Join(skillDir, "SKILL.md")); err != nil {
405				continue
406			}
407	
408			_ = os.RemoveAll(skillDir)
409		}
410	}
