434	func ensureProjectGitignoreRules(workingDir string, rules []string) error {
435		if len(rules) == 0 {
436			return nil
437		}
438		path := filepath.Join(workingDir, ".gitignore")
439		var content string
440		if raw, err := os.ReadFile(path); err == nil {
441			content = string(raw)
442		} else if !os.IsNotExist(err) {
443			return err
444		}
445	
446		trimmed := strings.TrimRight(content, "\n")
447		var missing []string
448		for _, rule := range rules {
449			rule = strings.TrimSpace(rule)
450			if rule == "" || containsExactLine(trimmed, rule) {
451				continue
452			}
453			missing = append(missing, rule)
454		}
455		if len(missing) == 0 {
456			return nil
457		}
458	
459		updated := trimmed
460		if updated != "" {
461			updated += "\n"
462		}
463		updated += "# DDx runtime scratch\n"
464		for _, rule := range missing {
465			updated += rule + "\n"
466		}
467		return os.WriteFile(path, []byte(updated), 0o644)
468	}
