470	func untrackLegacyRunStateFiles(ctx context.Context, workingDir string) error {
471		if workingDir == "" {
472			return nil
473		}
474		if out, err := gitpkg.Command(ctx, workingDir, "rev-parse", "--is-inside-work-tree").Output(); err != nil || strings.TrimSpace(string(out)) != "true" {
475			return nil
476		}
477		lsCmd := gitpkg.Command(ctx, workingDir, "ls-files", "-z", "--", ".ddx/run-state.json", ".ddx/run-state")
478		lsOut, err := lsCmd.Output()
479		if err != nil {
480			return err
481		}
482		if len(lsOut) == 0 {
483			return nil
484		}
485		rmCmd := gitpkg.Command(ctx, workingDir, "rm", "--cached", "-r", "-f", "-q", "--ignore-unmatch", "--", ".ddx/run-state.json", ".ddx/run-state")
486		if out, err := rmCmd.CombinedOutput(); err != nil {
487			msg := strings.TrimSpace(string(out))
488			if msg == "" {
489				return err
490			}
491			return fmt.Errorf("%s: %w", msg, err)
492		}
493		return nil
494	}
