505	// validateGitRepo is the pure business logic for git repository validation
506	func validateGitRepo(workingDir string) error {
507		// Use git rev-parse --git-dir to check if we're in a git repository.
508		// gitpkg.Command strips inherited GIT_DIR / GIT_WORK_TREE so the check
509		// reflects the actual directory, not an inherited git context.
510		gitCmd := gitpkg.Command(context.Background(), workingDir, "rev-parse", "--git-dir")
511		gitCmd.Stderr = nil // Suppress error output
512		if err := gitCmd.Run(); err != nil {
513			return fmt.Errorf("Error: ddx init must be run inside a git repository. Please run 'git init' first")
514		}
515	
516		return nil
517	}
518	
519	// findParentDDxWorkspace walks up from dir looking for a .ddx/ directory in
520	// any ancestor within the same git repository. Returns the ancestor path if
521	// found, or "" if none exists. Only checks within the git repo boundary to
522	// avoid false positives from stale .ddx/ directories elsewhere on the system.
523	func findParentDDxWorkspace(dir string) string {
524		abs, err := filepath.Abs(dir)
525		if err != nil {
526			return ""
527		}
528	
529		// Determine the git root to bound the upward walk.
530		gitRoot := gitpkg.FindProjectRoot(abs)
531		if gitRoot == abs {
532			// dir is already the git root — no parent to check within the repo.
533			return ""
534		}
535	
536		// Walk up from the parent to the git root (inclusive).
537		current := filepath.Dir(abs)
538		for {
539			candidate := ddxroot.InTree(current)
540			if info, statErr := os.Stat(candidate); statErr == nil && info.IsDir() {
541				return current
542			}
543			if current == gitRoot {
544				break
545			}
546			parent := filepath.Dir(current)
547			if parent == current {
548				break // filesystem root — shouldn't happen if gitRoot is set
549			}
550			current = parent
551		}
552		return ""
553	}
