555	// isExecuteBeadWorktree reports whether dir is inside an execute-bead
556	// workspace. Detects both linked worktrees and clone-backed attempt
557	// workspaces under the configured out-of-repo execution temp root. These
558	// are attempt-local repositories and must not be re-initialized.
559	func isExecuteBeadWorktree(dir string) bool {
560		abs, err := filepath.Abs(dir)
561		if err != nil {
562			return false
563		}
564		slash := filepath.ToSlash(abs)
565		// Legacy: a path component starting with .execute-bead-wt-.
566		for _, part := range strings.Split(slash, "/") {
567			if strings.HasPrefix(part, ".execute-bead-wt-") || strings.HasPrefix(part, ".execute-bead-clone-") {
568				return true
569			}
570		}
571		// Current: configured execution temp root.
572		currentContainer := filepath.ToSlash(config.ExecutionTempRoot(""))
573		if strings.HasPrefix(slash, currentContainer+"/") {
574			return true
575		}
576		// Legacy fallback: older binaries always used $TMPDIR/ddx-exec-wt.
577		legacyContainer := filepath.ToSlash(config.LegacyExecutionTempRoot())
578		if strings.HasPrefix(slash, legacyContainer+"/") {
579			return true
580		}
581		if override := os.Getenv("DDX_EXEC_WT_DIR"); override != "" {
582			if strings.HasPrefix(slash, filepath.ToSlash(override)+"/") {
583				return true
584			}
585		}
586		return false
587	}
