589	// AGENTS.md marker-delimited injection. Codex and other harnesses read
590	// AGENTS.md as primary guidance before work; users (and other tools) may
591	// add content of their own. We own only the content between markers —
592	// everything outside is preserved across re-runs of ddx init / ddx update.
593	const (
594		agentsMarkerStart = "<!-- DDX-AGENTS:START -->"
595		agentsMarkerEnd   = "<!-- DDX-AGENTS:END -->"
596	)
597	
598	// ddxAgentsBlock returns the DDx-owned block that gets injected between
599	// markers. Harness-neutral — says "the `ddx` skill", not "/ddx" (which
600	// would only mean something to Claude Code).
601	func ddxAgentsBlock() string {
602		return agentsMarkerStart + `
603	<!-- Managed by ddx init / ddx update. Edit outside these markers. -->
604	
605	# DDx
606	
607	This project uses [DDx](https://github.com/DocumentDrivenDX/ddx) for
608	document-driven development. Use the ` + "`" + `ddx` + "`" + ` skill for beads, work,
609	review, agents, and status — every skills-compatible harness (Claude
610	Code, OpenAI Codex, Gemini CLI, etc.) discovers it from
611	` + "`" + `.claude/skills/ddx/` + "`" + ` and ` + "`" + `.agents/skills/ddx/` + "`" + `.
612	
613	## Default Interactive Mode
614	
615	Broad conversational DDx prompts — queue orientation, planning, review,
616	guidance folding, spec alignment, and bead breakdown — use
617	` + "`" + `interactive-steward` + "`" + ` / ` + "`" + `queue_steward` + "`" + `. Explicit worker commands
618	(` + "`" + `ddx work` + "`" + `, ` + "`" + `ddx try <id>` + "`" + `, "execute bead ` + "`" + `<id>` + "`" + `") route to
619	` + "`" + `bead_execution` + "`" + `. Explicit code/doc edit requests route to
620	` + "`" + `direct_user_implementation` + "`" + `. Explicit review-only requests route to
621	` + "`" + `review` + "`" + `.
622	
623	` + "`" + `DDX_MODE=bead_execution` + "`" + ` overrides only the interactive queue-steward default.
624	It **never** overrides tracker, merge, commit, safety, or verification policy —
625	those apply in every mode.
626	
627	### Mutation policy
628	
629	- **read / plan / fresh-eyes review / fold guidance / align specs** — non-mutating
630	  by default; no tracker writes, no code edits.
631	- **Tracker mutation** (e.g. ` + "`" + `ddx bead create` + "`" + `, ` + "`" + `ddx bead update` + "`" + `) requires an
632	  explicit durable-output verb: "create a bead", "file this as work",
633	  "break down into beads".
634	- **Code edits** require explicit implementation intent ("fix this",
635	  "implement X") or ` + "`" + `bead_execution` + "`" + ` mode.
636	
637	## Files to commit
638	
639	After modifying any of these paths, stage and commit them:
640	
641	- ` + "`" + `.ddx/beads.jsonl` + "`" + ` — work item tracker
642	- ` + "`" + `.ddx/config.yaml` + "`" + ` — project configuration
643	- ` + "`" + `.agents/skills/ddx/` + "`" + ` — the ddx skill (shipped by ddx init)
644	- ` + "`" + `.claude/skills/ddx/` + "`" + ` — same skill, Claude Code location
645	- ` + "`" + `docs/` + "`" + ` — project documentation and artifacts
646	
647	## Conventions
648	
649	- Use ` + "`" + `ddx bead` + "`" + ` for work tracking (not custom issue files).
650	- Documents with ` + "`" + `ddx:` + "`" + ` frontmatter are tracked in the document graph.
651	- Run ` + "`" + `ddx doctor` + "`" + ` to check environment health.
652	- Run ` + "`" + `ddx doc stale` + "`" + ` to find documents needing review.
653	
654	## Merge Policy
655	
656	Branches containing ` + "`" + `ddx try` + "`" + ` or ` + "`" + `ddx work` + "`" + ` commits
657	carry a per-attempt execution audit trail:
658	
659	- ` + "`" + `chore: update tracker (execute-bead <TIMESTAMP>)` + "`" + ` — attempt heartbeats
660	- ` + "`" + `Merge bead <bead-id> attempt <TIMESTAMP>- into <branch>` + "`" + ` — successful lands
661	- ` + "`" + `feat|fix|...: ... [ddx-<id>]` + "`" + ` — substantive bead work
662	
663	Bead records store ` + "`" + `closing_commit_sha` + "`" + ` pointers into this history. Any
664	SHA rewrite breaks the trail. **Never squash, rebase, or filter** these
665	branches. Use only:
666	
667	- ` + "`" + `git merge --ff-only` + "`" + ` when the target is a strict ancestor, or
668	- ` + "`" + `git merge --no-ff` + "`" + ` when divergence exists
669	
670	Forbidden on execute-bead branches: ` + "`" + `gh pr merge --squash` + "`" + `,
671	` + "`" + `gh pr merge --rebase` + "`" + `, ` + "`" + `git rebase -i` + "`" + ` with fixup/squash/drop,
672	` + "`" + `git filter-branch` + "`" + `, ` + "`" + `git filter-repo` + "`" + `, and ` + "`" + `git commit --amend` + "`" + ` on
673	any commit already in the trail.
674	` + agentsMarkerEnd + "\n"
675	}
676	
677	// generateAgentsMD injects (or refreshes) the DDx-owned block in AGENTS.md.
678	// If AGENTS.md does not exist, it is created containing only the block.
679	// If AGENTS.md exists with markers, the content between markers is replaced
680	// and everything outside is preserved. If AGENTS.md exists without markers,
681	// the block is appended to the end.
682	func generateAgentsMD(workingDir string) {
683		agentsPath := filepath.Join(workingDir, "AGENTS.md")
684		block := ddxAgentsBlock()
685	
686		existing, err := os.ReadFile(agentsPath)
687		if err != nil {
688			// File doesn't exist — create with just the block.
689			_ = os.WriteFile(agentsPath, []byte(block), 0644)
690			return
691		}
692	
693		content := string(existing)
694		startIdx := strings.Index(content, agentsMarkerStart)
695		endIdx := strings.Index(content, agentsMarkerEnd)
696	
697		if startIdx == -1 || endIdx == -1 || endIdx < startIdx {
698			// Markers not present (or malformed). Append block to end.
699			separator := ""
700			if !strings.HasSuffix(content, "\n") {
701				separator = "\n"
702			}
703			if !strings.HasSuffix(content, "\n\n") {
704				separator += "\n"
705			}
706			updated := content + separator + block
707			_ = os.WriteFile(agentsPath, []byte(updated), 0644)
708			return
709		}
710	
711		// Markers present — replace the block between them.
712		endOfEndMarker := endIdx + len(agentsMarkerEnd)
713		// Include trailing newline after the end marker if present.
714		if endOfEndMarker < len(content) && content[endOfEndMarker] == '\n' {
715			endOfEndMarker++
716		}
717		updated := content[:startIdx] + block + content[endOfEndMarker:]
718		_ = os.WriteFile(agentsPath, []byte(updated), 0644)
719	}
