166	func removeStaleFilesFromInstall(oldFiles []string, newFiles []string) int {
167		if len(oldFiles) == 0 {
168			return 0
169		}
170	
171		newSet := make(map[string]bool, len(newFiles))
172		for _, f := range newFiles {
173			newSet[f] = true
174		}
175	
176		removed := 0
177		for _, f := range oldFiles {
178			if newSet[f] {
179				continue
180			}
181			if installPathContainsAny(f, newFiles) {
182				continue
183			}
184			expanded := registry.ExpandHome(f)
185			if err := os.RemoveAll(expanded); err == nil {
186				removed++
187			}
188		}
189		return removed
190	}
191	
192	func installPathContainsAny(parent string, files []string) bool {
193		parent = filepath.ToSlash(strings.TrimSuffix(parent, string(filepath.Separator)))
194		parent = strings.TrimSuffix(parent, "/")
195		if parent == "" {
196			return false
197		}
198		prefix := parent + "/"
199		for _, f := range files {
200			f = filepath.ToSlash(f)
201			if strings.HasPrefix(f, prefix) {
202				return true
203			}
204		}
205		return false
206	}
