208	// commitPluginChanges stages and commits plugin-related changes in the working tree.
209	// Non-fatal: if git operations fail (not a repo, nothing to commit), it's silently skipped.
210	func commitPluginChanges(name, version string) {
211		// Stage the project-local plugin tree and the skill copies.
212		paths := []string{ddxroot.JoinRelative("plugins", name) + string(filepath.Separator), ".agents/skills/",
213			".claude/skills/",
214		}
215		ctx := context.Background()
216		for _, p := range paths {
217			if _, err := os.Stat(p); err == nil {
218				gitAdd := internalgit.Command(ctx, "", "add", p)
219				_ = gitAdd.Run()
220			}
221		}
222	
223		// Check if there's anything to commit.
224		status := internalgit.Command(ctx, "", "diff", "--cached", "--quiet")
225		if status.Run() == nil {
226			return // nothing staged
227		}
228	
229		msg := fmt.Sprintf("chore: install %s %s", name, version)
230		gitCommit := internalgit.Command(ctx, "", "commit", "-m", msg)
231		_ = gitCommit.Run()
232	}
