553	func localSkillSourceRoots(pluginRoot string, mappings []registry.InstallMapping) ([]string, error) {
554		var roots []string
555		seen := map[string]bool{}
556		for _, mapping := range mappings {
557			source := strings.TrimSpace(mapping.Source)
558			if source == "" {
559				continue
560			}
561			candidate := filepath.Clean(filepath.Join(pluginRoot, filepath.FromSlash(source)))
562			info, err := os.Stat(candidate)
563			if os.IsNotExist(err) {
564				continue
565			}
566			if err != nil {
567				return nil, err
568			}
569			if !info.IsDir() {
570				return nil, fmt.Errorf("%s: skill source is not a directory", candidate)
571			}
572			if seen[candidate] {
573				continue
574			}
575			seen[candidate] = true
576			roots = append(roots, candidate)
577		}
578		return roots, nil
579	}
