641	func pluginManifestSkillSources(raw any) ([]string, error) {
642		switch v := raw.(type) {
643		case nil:
644			return nil, nil
645		case string:
646			source := cleanPluginManifestPath(v)
647			if source == "" {
648				return nil, nil
649			}
650			return []string{source}, nil
651		case []any:
652			var sources []string
653			for _, item := range v {
654				text, ok := item.(string)
655				if !ok {
656					return nil, fmt.Errorf("skills entries must be strings")
657				}
658				source := cleanPluginManifestPath(text)
659				if source != "" {
660					sources = append(sources, source)
661				}
662			}
663			return sources, nil
664		default:
665			return nil, fmt.Errorf("skills must be a string or array of strings")
666		}
667	}
