685	func addLocalOverlayIgnores(repoRoot string, paths []string) error {
686		excludePath := filepath.Join(repoRoot, ".git", "info", "exclude")
687		if err := os.MkdirAll(filepath.Dir(excludePath), 0o755); err != nil {
688			return err
689		}
690		existing, _ := os.ReadFile(excludePath)
691		text := string(existing)
692	
693		var additions []string
694		for _, p := range paths {
695			pattern := filepath.ToSlash(p)
696			candidates := []string{pattern}
697			if !strings.HasSuffix(pattern, "/") {
698				candidates = append(candidates, pattern+"/")
699			}
700			for _, candidate := range candidates {
701				if !strings.Contains(text, "\n"+candidate+"\n") && !strings.HasPrefix(text, candidate+"\n") {
702					additions = append(additions, candidate)
703				}
704			}
705		}
706		if len(additions) == 0 {
707			return nil
708		}
709	
710		var sb strings.Builder
711		if len(existing) > 0 && !strings.HasSuffix(text, "\n") {
712			sb.WriteString("\n")
713		}
714		if !strings.Contains(text, "# DDx local plugin overlays") {
715			sb.WriteString("\n# DDx local plugin overlays\n")
716		}
717		for _, pattern := range additions {
718			sb.WriteString(pattern)
719			sb.WriteString("\n")
720		}
721		return os.WriteFile(excludePath, append(existing, []byte(sb.String())...), 0o644)
722	}
