724	func filterLocalInstallValidationIssues(root string, issues []registry.ValidationIssue) []registry.ValidationIssue {
725		filtered := issues[:0]
726		roots := localInstallRootAliases(root)
727		ignoreCache := map[string]bool{}
728		for _, issue := range issues {
729			if rel, ok := localInstallIssueRel(roots, issue.Path); ok &&
730				(shouldSkipLocalInstallIssue(rel) || localInstallPathIsGitIgnored(root, rel, ignoreCache)) {
731				continue
732			}
733			filtered = append(filtered, issue)
734		}
735		return filtered
736	}
737	
738	// localInstallPathIsGitIgnored reports whether rel (a slash path relative to
739	// the local install source root) is gitignored in the source repository.
740	// ddx install --local must not fail validation on broken symlinks that live
741	// under gitignored scratch/tmp paths (e.g. doctor/home/.codex/tmp/...) the
742	// operator never intended to ship. Returns false when the source is not a git
743	// repo or git is unavailable, leaving the well-known-prefix skip list as the
744	// fallback.
745	func localInstallPathIsGitIgnored(root, rel string, cache map[string]bool) bool {
746		rel = strings.TrimSpace(rel)
747		if rel == "" {
748			return false
749		}
750		if cached, ok := cache[rel]; ok {
751			return cached
752		}
753		// git check-ignore exits 0 when the path is ignored, 1 when it is not, and
754		// 128 when the source is not a git repository — treat anything but 0 as
755		// "not ignored" so non-git sources fall through to the prefix skip list.
756		cmd := internalgit.Command(context.Background(), root, "check-ignore", "-q", "--", filepath.FromSlash(rel))
757		ignored := cmd.Run() == nil
758		cache[rel] = ignored
759		return ignored
760	}
