299	func breakStaleBootstrapLock(lockDir string) bool {
300		acquiredAt, err := os.ReadFile(filepath.Join(lockDir, "acquired_at"))
301		if err == nil {
302			if ts, parseErr := time.Parse(time.RFC3339Nano, strings.TrimSpace(string(acquiredAt))); parseErr == nil && time.Since(ts) > bootstrapLockStaleAge {
303				_ = os.RemoveAll(lockDir)
304				return true
305			}
306		}
307		return false
308	}
