// runInitGlobal handles the --global mode of ddx init: one-time machine setup.
func (f *CommandFactory) runInitGlobal(cmd *cobra.Command) error {
	silent, _ := cmd.Flags().GetBool("silent")
	if !silent {
		_, _ = fmt.Fprint(cmd.OutOrStdout(), "🌐 Setting up DDx global machine layer...\n")
	}
	if err := initGlobal(); err != nil {
		cmd.SilenceUsage = true
		return err
	}
	if !silent {
		_, _ = fmt.Fprint(cmd.OutOrStdout(), "✅ DDx global setup complete!\n")
	}
	return nil
}

// initGlobal installs the bundled ddx plugin to the global layer, writes a
// global config, and creates HOME-level agent-tier skill links.
func initGlobal() error {
	globalDir := ddxroot.GlobalDir()
	globalPluginDir := filepath.Join(globalDir, "plugins", "ddx")

	// Install the embedded plugin tree into the global plugin dir.
	if err := os.MkdirAll(globalPluginDir, 0o755); err != nil {
		return fmt.Errorf("creating global plugin dir: %w", err)
	}
	if err := copyFSInto(defaultplugin.FS(), globalPluginDir); err != nil {
		return fmt.Errorf("installing global plugin: %w", err)
	}

	// Create HOME-level agent-tier skill links.
	home, err := os.UserHomeDir()
	if err != nil {
		return fmt.Errorf("resolving home dir: %w", err)
	}
	skillSrc := filepath.Join(globalPluginDir, "skills", "ddx")
	for _, harness := range []string{".claude", ".agents"} {
		dst := filepath.Join(home, harness, "skills", "ddx")
		if err := os.MkdirAll(filepath.Dir(dst), 0o755); err != nil {
			return fmt.Errorf("creating %s/skills dir: %w", harness, err)
		}
		if _, err := os.Lstat(dst); err == nil {
			if err := os.RemoveAll(dst); err != nil {
				return fmt.Errorf("removing existing %s: %w", dst, err)
			}
		}
		if err := os.Symlink(skillSrc, dst); err != nil {
			return fmt.Errorf("creating skill link %s: %w", dst, err)
		}
	}

	// Write ${XDG_DATA_HOME}/ddx/global/config.yaml with convention defaults.
	configPath := filepath.Join(globalDir, "config.yaml")
	configContent := "version: \"1.0\"\nlibrary:\n  path: plugins/ddx\n"
	if err := os.WriteFile(configPath, []byte(configContent), 0o644); err != nil {
		return fmt.Errorf("writing global config: %w", err)
	}

	return nil
}

// copyFSInto copies all regular files from src into dst, preserving the
// relative path layout.
func copyFSInto(src iofs.FS, dst string) error {
	return iofs.WalkDir(src, ".", func(p string, d iofs.DirEntry, err error) error {
		if err != nil {
			return err
		}
		if p == "." {
			return nil
		}
		target := filepath.Join(dst, filepath.FromSlash(p))
		if d.IsDir() {
			return os.MkdirAll(target, 0o755)
		}
		if !d.Type().IsRegular() {
			return nil
		}
		data, readErr := iofs.ReadFile(src, p)
		if readErr != nil {
			return readErr
		}
		if err := os.MkdirAll(filepath.Dir(target), 0o755); err != nil {
			return err
		}
		return os.WriteFile(target, data, 0o644)
	})
}

